		if relErr != nil {
			rel = artifactPath
		}

		id := sidecar.DDx.ID
		if id == "" {
			id = "sidecar:" + rel
		}

		title := sidecar.DDx.Title
		if title == "" {
			title = filepath.Base(artifactPath)
