import (
	"context"

	agentlib "github.com/DocumentDrivenDX/fizeau"
)

// profileSurfaceToDDx maps agentlib ProfileSurface names to DDx catalog surface
// identifiers. native-anthropic is absent: the embedded agent harness in DDx
// uses the "embedded-openai" surface; native-openai wins for that slot.
var profileSurfaceToDDx = map[string]string{
	"native-openai": "embedded-openai",
	"claude":        "claude",
	"codex":         "codex",
}

// ApplyCatalogFromService overlays agentlib profile data onto a DDx Catalog.
// It enumerates profiles via svc.ListProfiles and resolves surface-specific
// models via svc.ResolveProfile. Individual profile errors are silently skipped;
// the builtin catalog remains the fallback for any unresolvable entry.
func ApplyCatalogFromService(ctx context.Context, cat *Catalog, svc agentlib.FizeauService) {
	if cat == nil || svc == nil {
		return
	}
	profiles, err := svc.ListProfiles(ctx)
	if err != nil || len(profiles) == 0 {
		return
	}
	for _, p := range profiles {
		resolved, err := svc.ResolveProfile(ctx, p.Name)
		if err != nil || resolved == nil {
			if p.Deprecated {
				cat.AddOrReplace(CatalogEntry{
					Ref:        p.Name,
					Deprecated: true,
					ReplacedBy: p.Replacement,
				})
			}
			continue
		}
		surfaces := make(map[string]string, len(resolved.Surfaces))
		for _, s := range resolved.Surfaces {
			dst, ok := profileSurfaceToDDx[s.Name]
			if !ok || s.Model == "" {
				continue
			}
			surfaces[dst] = s.Model
		}
		if len(surfaces) == 0 && !resolved.Deprecated {
			continue
		}
		cat.AddOrReplace(CatalogEntry{
			Ref:        p.Name,
			Surfaces:   surfaces,
			Deprecated: resolved.Deprecated,
			ReplacedBy: resolved.Replacement,
		})
	}
}

package agent

// CatalogEntry defines a logical model ref or profile's surface mappings.
// DDx uses this to project a ref (alias, profile, or canonical name) onto
// harness-specific surfaces and to surface deprecation/replacement metadata.
type CatalogEntry struct {
	// Ref is the logical name (e.g. "qwen3", "cheap", "fast", "smart").
	Ref string
	// Surfaces maps a harness surface identifier to the concrete model string
	// to pass to that harness. A ref absent from a surface's map means that
	// surface cannot serve the ref.
	Surfaces map[string]string
	// Deprecated marks this ref as deprecated.
	Deprecated bool
	// ReplacedBy is the canonical replacement ref when Deprecated is true.
	ReplacedBy string
	// Blocked marks this ref as blocked; Resolve() returns ok=false for blocked entries.
	Blocked bool
}

// DeprecatedPin records a deprecated explicit model version string.
// Use this for exact concrete model pins (e.g. "claude-opus-4-5") that are
// stale — as opposed to logical alias deprecations in CatalogEntry.
type DeprecatedPin struct {
	// Pin is the deprecated exact model string (e.g. "claude-opus-4-5").
	Pin string
	// ReplacedBy is the canonical replacement: a catalog ref (e.g. "smart")
	// or a newer exact model string (e.g. "claude-opus-4-6").
	ReplacedBy string
	// Surface constrains the deprecation to a specific harness surface.
	// Empty means the pin is deprecated across all surfaces.
	Surface string
}

// Catalog holds the shared DDx model catalog used for harness routing.
// It maps logical refs to harness-surface-specific concrete model strings.
// This is the authoritative source for aliases, profiles, canonical targets,
// and deprecation metadata across harness surfaces.
type Catalog struct {
	entries         map[string]CatalogEntry
	deprecatedPins  map[string]DeprecatedPin // keyed by Pin
	blockedModelIDs map[string]bool          // concrete model IDs that routing must never select
}

// catalog returns the catalog to use for runtime model metadata checks.
// Defaults to BuiltinCatalog.
func (r *Runner) catalog() *Catalog {
	if r.Catalog != nil {
		return r.Catalog
	}
	return BuiltinCatalog
}

// NewCatalog creates a Catalog from a slice of entries.
func NewCatalog(entries []CatalogEntry) *Catalog {
	c := &Catalog{entries: make(map[string]CatalogEntry, len(entries))}
	for _, e := range entries {
		c.entries[e.Ref] = e
	}
	return c
}

// NewCatalogWithPins creates a Catalog from entries and deprecated pin records.
func NewCatalogWithPins(entries []CatalogEntry, pins []DeprecatedPin) *Catalog {
	c := NewCatalog(entries)
	c.deprecatedPins = make(map[string]DeprecatedPin, len(pins))
	for _, p := range pins {
		c.deprecatedPins[p.Pin] = p
	}
	return c
}

// Clone returns an independent copy of the catalog.
func (c *Catalog) Clone() *Catalog {
	if c == nil {
		return NewCatalog(nil)
	}
	clone := &Catalog{
		entries:         make(map[string]CatalogEntry, len(c.entries)),
		deprecatedPins:  make(map[string]DeprecatedPin, len(c.deprecatedPins)),
		blockedModelIDs: make(map[string]bool, len(c.blockedModelIDs)),
	}
	for ref, entry := range c.entries {
		surfaces := make(map[string]string, len(entry.Surfaces))
		for surface, model := range entry.Surfaces {
			surfaces[surface] = model
		}
		entry.Surfaces = surfaces
		clone.entries[ref] = entry
	}
	for pin, entry := range c.deprecatedPins {
		clone.deprecatedPins[pin] = entry
	}
	for id, blocked := range c.blockedModelIDs {
		clone.blockedModelIDs[id] = blocked
	}
	return clone
}

// AddOrReplace inserts or replaces a catalog entry by Ref.
func (c *Catalog) AddOrReplace(entry CatalogEntry) {
	if c.entries == nil {
		c.entries = make(map[string]CatalogEntry)
	}
	c.entries[entry.Ref] = entry
}

// AddBlockedModelID marks a concrete model ID as blocked.
// Resolve() returns ok=false for any model that resolves to a blocked ID.
func (c *Catalog) AddBlockedModelID(id string) {
	if c.blockedModelIDs == nil {
		c.blockedModelIDs = make(map[string]bool)
	}
	c.blockedModelIDs[id] = true
}

// CheckDeprecatedPin returns the DeprecatedPin entry for an explicit model
// string, or ok=false if the pin is not deprecated.
// If surface is non-empty and the pin entry has a Surface set, the match is
// narrowed to that surface only.
func (c *Catalog) CheckDeprecatedPin(pin, surface string) (DeprecatedPin, bool) {
	if c.deprecatedPins == nil {
		return DeprecatedPin{}, false
	}
	dp, ok := c.deprecatedPins[pin]
	if !ok {
		return DeprecatedPin{}, false
	}
	if dp.Surface != "" && surface != "" && dp.Surface != surface {
		return DeprecatedPin{}, false
	}
	return dp, true
}

// Resolve returns the concrete model string for a ref on the given surface.
// Returns ("", false) if the ref is unknown, not mapped to this surface,
// the entry is blocked, or the resolved concrete model is blocked.
func (c *Catalog) Resolve(ref, surface string) (string, bool) {
	e, ok := c.entries[ref]
	if !ok {
		return "", false
	}
	if e.Blocked {
		return "", false
	}
	model, ok := e.Surfaces[surface]
	if !ok {
		return "", false
	}
	if c.blockedModelIDs[model] {
		return "", false
	}
	return model, true
}

// BuiltinCatalog is the DDx shared routing catalog built from the YAML seed.
// Tier→surface→model assignments come from DefaultModelCatalogYAML so the data
// lives in one place. Policy aliases (qwen3, codex-mini) and deprecated pins
// are added here as they are routing policy decisions, not model metadata.
var BuiltinCatalog = buildBuiltinCatalog()

func buildBuiltinCatalog() *Catalog {
	yml := DefaultModelCatalogYAML()

	// Build tier entries from YAML seed.
	var entries []CatalogEntry
	for tierName, tierDef := range yml.Tiers {
		entry := CatalogEntry{
			Ref:      tierName,
			Surfaces: make(map[string]string, len(tierDef.Surfaces)),
		}
		for surface, model := range tierDef.Surfaces {
			entry.Surfaces[surface] = model
		}
		entries = append(entries, entry)
	}

	// Policy aliases: logical names not tied to a tier profile.
	entries = append(entries,
		// qwen3 is only available via the embedded OpenAI-compatible surface.
		CatalogEntry{
			Ref:      "qwen3",
			Surfaces: map[string]string{"embedded-openai": "qwen/qwen3-coder-next"},
		},
		// codex-mini is a deprecated alias for the cheap codex model.
		CatalogEntry{
			Ref:        "codex-mini",
			Surfaces:   map[string]string{"codex": "gpt-5.4-mini"},
			Deprecated: true,
			ReplacedBy: "cheap",
		},
	)

	pins := []DeprecatedPin{
		// Stale exact version strings for the claude (Anthropic) family.
		{Pin: "claude-opus-4-5", Surface: "claude", ReplacedBy: "claude-opus-4-6"},
		{Pin: "claude-3-5-sonnet-20241022", Surface: "claude", ReplacedBy: "claude-sonnet-4-6"},
		{Pin: "claude-3-opus-20240229", Surface: "claude", ReplacedBy: "claude-opus-4-6"},
		{Pin: "claude-3-sonnet-20240229", Surface: "claude", ReplacedBy: "claude-sonnet-4-6"},
		// Stale exact version strings for the codex (OpenAI) family.
		{Pin: "gpt-4o", Surface: "codex", ReplacedBy: "gpt-5.4-mini"},
		{Pin: "gpt-4-turbo", Surface: "codex", ReplacedBy: "gpt-5.4"},
		{Pin: "o1-2024-12-17", Surface: "codex", ReplacedBy: "gpt-5.4"},
	}

	return NewCatalogWithPins(entries, pins)
}

package artifacttypes

import (
	"fmt"
	"sort"
	"strings"
)

// Example describes a worked example for an artifact type.
type Example struct {
	Path        string
	Description string
}

// Type is the normalized artifact-type record produced by the loader.
type Type struct {
	Plugin         string
	TypeID         string
	Name           string
	Description    string
	Prefix         string
	Pattern        string
	Phase          string
	TemplatePath   string
	PromptPath     string
	Examples       []Example
	SourceMetaPath string
}

// Index is the normalized in-memory lookup index for discovered artifact types.
type Index struct {
	Types    []Type
	byKey    map[string]int
	byPrefix map[string]int
	byPlugin map[string][]int
}

// Clone returns a deep copy of the index.
func (i *Index) Clone() *Index {
	if i == nil {
		return nil
	}
	clone := &Index{Types: make([]Type, len(i.Types))}
	for idx, typ := range i.Types {
		clone.Types[idx] = cloneType(typ)
	}
	clone.rebuildLookups()
	return clone
}

// ByPlugin returns all types belonging to plugin in deterministic order.
func (i *Index) ByPlugin(plugin string) []Type {
	if i == nil || len(i.Types) == 0 {
		return nil
	}
	idxs := i.byPlugin[plugin]
	if len(idxs) == 0 {
		return nil
	}
	out := make([]Type, 0, len(idxs))
	for _, idx := range idxs {
		out = append(out, cloneType(i.Types[idx]))
	}
	return out
}

// Lookup returns the type for a plugin/typeID pair.
func (i *Index) Lookup(plugin, typeID string) (Type, bool) {
	if i == nil {
		return Type{}, false
	}
	idx, ok := i.byKey[keyFor(plugin, typeID)]
	if !ok {
		return Type{}, false
	}
	return cloneType(i.Types[idx]), true
}

// LookupPrefix returns the first type that claims prefix.
func (i *Index) LookupPrefix(prefix string) (Type, bool) {
	if i == nil {
		return Type{}, false
	}
	idx, ok := i.byPrefix[prefix]
	if !ok {
		return Type{}, false
	}
	return cloneType(i.Types[idx]), true
}

func buildIndex(types []Type) (*Index, error) {
	sorted := make([]Type, len(types))
	copy(sorted, types)
	sort.Slice(sorted, func(i, j int) bool {
		if sorted[i].Plugin != sorted[j].Plugin {
			return sorted[i].Plugin < sorted[j].Plugin
		}
		if sorted[i].TypeID != sorted[j].TypeID {
			return sorted[i].TypeID < sorted[j].TypeID
		}
		return sorted[i].SourceMetaPath < sorted[j].SourceMetaPath
	})

	idx := &Index{
		Types:    sorted,
		byKey:    make(map[string]int, len(sorted)),
		byPrefix: make(map[string]int, len(sorted)),
		byPlugin: make(map[string][]int, len(sorted)),
	}

	for i, typ := range sorted {
		if typ.Plugin == "" {
			return nil, fmt.Errorf("artifact type %q missing plugin name", typ.TypeID)
		}
		if typ.TypeID == "" {
			return nil, fmt.Errorf("artifact type in plugin %q missing type id", typ.Plugin)
		}
		key := keyFor(typ.Plugin, typ.TypeID)
		if _, exists := idx.byKey[key]; exists {
			return nil, fmt.Errorf("duplicate artifact type %s/%s", typ.Plugin, typ.TypeID)
		}
		idx.byKey[key] = i
		idx.byPlugin[typ.Plugin] = append(idx.byPlugin[typ.Plugin], i)
		if typ.Prefix != "" {
			if _, exists := idx.byPrefix[typ.Prefix]; exists {
				return nil, fmt.Errorf("duplicate artifact type prefix %q", typ.Prefix)
			}
			idx.byPrefix[typ.Prefix] = i
		}
	}
	return idx, nil
}

func (i *Index) rebuildLookups() {
	i.byKey = make(map[string]int, len(i.Types))
	i.byPrefix = make(map[string]int, len(i.Types))
	i.byPlugin = make(map[string][]int, len(i.Types))
	for idx, typ := range i.Types {
		i.byKey[keyFor(typ.Plugin, typ.TypeID)] = idx
		i.byPlugin[typ.Plugin] = append(i.byPlugin[typ.Plugin], idx)
		if typ.Prefix != "" {
			i.byPrefix[typ.Prefix] = idx
		}
	}
}

func cloneType(typ Type) Type {
	clone := typ
	if len(typ.Examples) > 0 {
		clone.Examples = append([]Example(nil), typ.Examples...)
	}
	return clone
}

func keyFor(plugin, typeID string) string {
	return plugin + "\x00" + typeID
}

func humanizeTypeID(typeID string) string {
	if typeID == "" {
		return ""
	}
	fields := strings.FieldsFunc(typeID, func(r rune) bool {
		return r == '-' || r == '_' || r == '/'
	})
	if len(fields) == 0 {
		return strings.Title(typeID)
	}
	for i, field := range fields {
		fields[i] = strings.ToUpper(field[:1]) + strings.ToLower(field[1:])
	}
	return strings.Join(fields, " ")
}

package artifacttypes

import (
	"fmt"
	"os"
	"path"
	"path/filepath"
	"sort"
	"strings"
	"sync"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/registry"
	"gopkg.in/yaml.v3"
)

// Loader discovers artifact types under an installed plugin root and caches
// the normalized result until the on-disk mtimes change.
type Loader struct {
	mu    sync.Mutex
	cache map[string]cacheEntry
}

type cacheEntry struct {
	index     *Index
	snapshots []snapshot
}

type snapshot struct {
	path    string
	exists  bool
	modTime time.Time
}

type metaDoc struct {
	Artifact struct {
		Name     string `yaml:"name"`
		ID       string `yaml:"id"`
		Type     string `yaml:"type"`
		Prefix   string `yaml:"prefix"`
		Phase    string `yaml:"phase"`
		Optional bool   `yaml:"optional"`
	} `yaml:"artifact"`
	Description string `yaml:"description"`
	Output      struct {
		Location string `yaml:"location"`
		Format   string `yaml:"format"`
		Naming   string `yaml:"naming"`
	} `yaml:"output"`
	Prompts struct {
		Generation string `yaml:"generation"`
		Review     string `yaml:"review"`
	} `yaml:"prompts"`
	Template struct {
		File string `yaml:"file"`
	} `yaml:"template"`
	Examples []struct {
		File        string `yaml:"file"`
		Description string `yaml:"description"`
	} `yaml:"examples"`
	IDFormat struct {
		Prefix      string `yaml:"prefix"`
		Pattern     string `yaml:"pattern"`
		Example     string `yaml:"example"`
		Description string `yaml:"description"`
	} `yaml:"id_format"`
	Name   string `yaml:"name"`
	ID     string `yaml:"id"`
	Prefix string `yaml:"prefix"`
	Phase  string `yaml:"phase"`
}

// NewLoader creates an empty loader with no cached roots.
func NewLoader() *Loader {
	return &Loader{cache: make(map[string]cacheEntry)}
}

// Load discovers artifact types for pluginRoot.
func (l *Loader) Load(pluginRoot string) (*Index, error) {
	if strings.TrimSpace(pluginRoot) == "" {
		return nil, fmt.Errorf("artifacttypes: plugin root is empty")
	}

	rootCanonical, err := canonicalPath(pluginRoot)
	if err != nil {
		return nil, err
	}

	l.mu.Lock()
	defer l.mu.Unlock()

	if entry, ok := l.cache[rootCanonical]; ok {
		if ok, err := entry.valid(); err == nil && ok {
			return entry.index.Clone(), nil
		}
	}

	pluginName, roots, snapshots, err := loadPluginRoots(rootCanonical)
	if err != nil {
		return nil, err
	}

	types, scannedSnapshots, err := scanPlugin(rootCanonical, pluginName, roots)
	if err != nil {
		return nil, err
	}

	snapshots = append(snapshots, scannedSnapshots...)
	index, err := buildIndex(types)
	if err != nil {
		return nil, err
	}
	l.cache[rootCanonical] = cacheEntry{index: index.Clone(), snapshots: snapshots}
	return index.Clone(), nil
}

func (e cacheEntry) valid() (bool, error) {
	for _, snap := range e.snapshots {
		info, err := os.Stat(snap.path)
		if err != nil {
			if os.IsNotExist(err) {
				return !snap.exists, nil
			}
			return false, err
		}
		if !snap.exists {
			return false, nil
		}
		if !info.ModTime().Equal(snap.modTime) {
			return false, nil
		}
	}
	return true, nil
}

func loadPluginRoots(rootCanonical string) (string, []string, []snapshot, error) {
	snapshots := []snapshot{recordSnapshot(rootCanonical)}
	manifest, _, err := registry.LoadPackageManifest(rootCanonical)
	if err != nil {
		if os.IsNotExist(err) {
			return filepath.Base(rootCanonical), []string{"workflows"}, snapshots, nil
		}
		// If the manifest parsed but had issues, still use the partial package
		// so artifact roots can be resolved from the preserved Extra map.
		if manifest == nil {
			return "", nil, snapshots, err
		}
	}
	if manifest == nil {
		return filepath.Base(rootCanonical), []string{"workflows"}, snapshots, nil
	}

	roots, err := artifactTypeRoots(manifest)
	if err != nil {
		return "", nil, snapshots, err
	}
	pluginName := strings.TrimSpace(manifest.Name)
	if pluginName == "" {
		pluginName = filepath.Base(rootCanonical)
	}
	snapshots = append(snapshots, recordSnapshot(filepath.Join(rootCanonical, "package.yaml")))
	return pluginName, roots, snapshots, nil
}

func artifactTypeRoots(pkg *registry.Package) ([]string, error) {
	if pkg == nil {
		return []string{"workflows"}, nil
	}
	extra, ok := pkg.Extra["artifact_type_roots"]
	if !ok {
		return []string{"workflows"}, nil
	}

	roots, err := stringsSlice(extra)
	if err != nil {
		return nil, fmt.Errorf("artifact_type_roots: %w", err)
	}
	if len(roots) == 0 {
		return []string{}, nil
	}
	return roots, nil
}

func stringsSlice(raw any) ([]string, error) {
	switch v := raw.(type) {
	case []string:
		return append([]string(nil), v...), nil
	case []any:
		out := make([]string, 0, len(v))
		for _, item := range v {
			s, ok := item.(string)
			if !ok {
				return nil, fmt.Errorf("expected string entries, got %T", item)
			}
			out = append(out, s)
		}
		return out, nil
	default:
		return nil, fmt.Errorf("expected list, got %T", raw)
	}
}

func scanPlugin(rootCanonical, pluginName string, patterns []string) ([]Type, []snapshot, error) {
	if len(patterns) == 0 {
		return []Type{}, []snapshot{recordSnapshot(rootCanonical)}, nil
	}

	concreteRoots, err := resolveRoots(rootCanonical, patterns)
	if err != nil {
		return nil, nil, err
	}

	var (
		types     []Type
		snapshots []snapshot
	)
	for _, root := range concreteRoots {
		snapshots = append(snapshots, recordSnapshot(root))
		err := filepath.WalkDir(root, func(p string, d os.DirEntry, walkErr error) error {
			if walkErr != nil {
				return walkErr
			}
			snapshots = append(snapshots, recordSnapshot(p))
			if !d.IsDir() {
				if filepath.Base(p) != "meta.yml" {
					return nil
				}
				typ, extraSnaps, err := parseTypeMeta(rootCanonical, pluginName, p)
				if err != nil {
					return err
				}
				types = append(types, typ)
				snapshots = append(snapshots, extraSnaps...)
			}
			return nil
		})
		if err != nil {
			return nil, nil, err
		}
	}
	return types, snapshots, nil
}

func parseTypeMeta(rootCanonical, pluginName, metaPath string) (Type, []snapshot, error) {
	metaCanonical, err := canonicalPath(metaPath)
	if err != nil {
		return Type{}, nil, err
	}
	if err := ensureWithinRoot(rootCanonical, metaCanonical); err != nil {
		return Type{}, nil, err
	}

	baseDir := filepath.Dir(metaCanonical)
	templatePath, err := resolveRelativeFile(rootCanonical, baseDir, "template.md")
	if err != nil {
		return Type{}, nil, fmt.Errorf("%s: template.md: %w", metaPath, err)
	}
	promptPath, err := resolveRelativeFile(rootCanonical, baseDir, "prompt.md")
	if err != nil {
		return Type{}, nil, fmt.Errorf("%s: prompt.md: %w", metaPath, err)
	}

	raw, err := os.ReadFile(metaCanonical)
	if err != nil {
		return Type{}, nil, fmt.Errorf("read %s: %w", metaPath, err)
	}
	var doc metaDoc
	if err := yaml.Unmarshal(raw, &doc); err != nil {
		return Type{}, nil, fmt.Errorf("parse %s: %w", metaPath, err)
	}

	typeID := firstNonEmpty(doc.Artifact.ID, doc.ID, filepath.Base(baseDir))
	name := firstNonEmpty(doc.Artifact.Name, doc.Name, humanizeTypeID(typeID))
	pattern := firstNonEmpty(doc.Output.Naming, doc.IDFormat.Pattern, doc.Output.Location)
	prefix := firstNonEmpty(doc.Artifact.Prefix, doc.IDFormat.Prefix, doc.Prefix, inferPrefix(pattern), inferPrefixFromName(name), strings.ToUpper(typeID))
	phase := firstNonEmpty(doc.Artifact.Phase, doc.Phase, inferPhase(metaCanonical, rootCanonical))
	description := strings.TrimSpace(doc.Description)

	examples := make([]Example, 0, len(doc.Examples))
	if len(doc.Examples) > 0 {
		for _, ex := range doc.Examples {
			exPath, err := resolveRelativeFile(rootCanonical, baseDir, ex.File)
			if err != nil {
				return Type{}, nil, fmt.Errorf("%s: examples[%q]: %w", metaPath, ex.File, err)
			}
			rel, err := filepath.Rel(rootCanonical, exPath)
			if err != nil {
				return Type{}, nil, fmt.Errorf("%s: examples[%q]: %w", metaPath, ex.File, err)
			}
			examples = append(examples, Example{
				Path:        filepath.ToSlash(rel),
				Description: strings.TrimSpace(ex.Description),
			})
		}
	} else {
		examplePath, err := resolveRelativeFile(rootCanonical, baseDir, "example.md")
		if err == nil {
			rel, relErr := filepath.Rel(rootCanonical, examplePath)
			if relErr != nil {
				return Type{}, nil, relErr
			}
			examples = append(examples, Example{Path: filepath.ToSlash(rel)})
		}
	}

	metaRel, err := filepath.Rel(rootCanonical, metaCanonical)
	if err != nil {
		return Type{}, nil, err
	}
	templateRel, err := filepath.Rel(rootCanonical, templatePath)
	if err != nil {
		return Type{}, nil, err
	}
	promptRel, err := filepath.Rel(rootCanonical, promptPath)
	if err != nil {
		return Type{}, nil, err
	}

	typ := Type{
		Plugin:         pluginName,
		TypeID:         typeID,
		Name:           name,
		Description:    description,
		Prefix:         prefix,
		Pattern:        pattern,
		Phase:          phase,
		TemplatePath:   filepath.ToSlash(templateRel),
		PromptPath:     filepath.ToSlash(promptRel),
		Examples:       examples,
		SourceMetaPath: filepath.ToSlash(metaRel),
	}
	return typ, []snapshot{recordSnapshot(metaCanonical)}, nil
}

func resolveRoots(rootCanonical string, patterns []string) ([]string, error) {
	var roots []string
	for _, raw := range patterns {
		pattern := strings.TrimSpace(filepath.ToSlash(raw))
		if pattern == "" {
			continue
		}
		if err := validateRelativePattern(pattern); err != nil {
			return nil, err
		}
		if hasGlob(pattern) {
			matches, err := globDirs(rootCanonical, pattern)
			if err != nil {
				return nil, err
			}
			roots = append(roots, matches...)
			continue
		}
		candidate := filepath.Join(rootCanonical, filepath.FromSlash(pattern))
		canonical, err := canonicalPath(candidate)
		if err != nil {
			return nil, err
		}
		if err := ensureWithinRoot(rootCanonical, canonical); err != nil {
			return nil, err
		}

		}
		info, err := os.Stat(canonical)
		if err != nil {
			if os.IsNotExist(err) {
				continue
			}
			return nil, err
		}
		if !info.IsDir() {
			continue
		}
		roots = append(roots, canonical)
	}
	roots = dedupeSortedPaths(roots)
	return roots, nil
}

func globDirs(rootCanonical, pattern string) ([]string, error) {
	var matches []string
	err := filepath.WalkDir(rootCanonical, func(p string, d os.DirEntry, walkErr error) error {
		if walkErr != nil {
			return walkErr
		}
		if !d.IsDir() {
			return nil
		}
		rel, err := filepath.Rel(rootCanonical, p)
		if err != nil {
			return err
		}
		rel = filepath.ToSlash(rel)
		if rel == "." {
			rel = ""
		}
		if matchGlobPath(pattern, rel) {
			matches = append(matches, p)
		}
		return nil
	})
	if err != nil {
		return nil, err
	}
	return dedupeSortedPaths(matches), nil
}

func dedupeSortedPaths(paths []string) []string {
	if len(paths) == 0 {
		return nil
	}
	sort.Strings(paths)
	out := paths[:0]
	var prev string
	for i, p := range paths {
		if i == 0 || p != prev {
			out = append(out, p)
			prev = p
		}
	}
	return append([]string(nil), out...)
}

func matchGlobPath(pattern, candidate string) bool {
	pp := splitPath(pattern)
	cp := splitPath(candidate)
	return matchGlobSegments(pp, cp)
}

func matchGlobSegments(pattern, candidate []string) bool {
	if len(pattern) == 0 {
		return len(candidate) == 0
	}
	if pattern[0] == "**" {
		if len(pattern) == 1 {
			return true
		}
		for i := 0; i <= len(candidate); i++ {
			if matchGlobSegments(pattern[1:], candidate[i:]) {
				return true
			}
		}
		return false
	}
	if len(candidate) == 0 {
		return false
	}
	ok, err := path.Match(pattern[0], candidate[0])
	if err != nil || !ok {
		return false
	}
	return matchGlobSegments(pattern[1:], candidate[1:])
}

func splitPath(s string) []string {
	parts := strings.Split(filepath.ToSlash(strings.TrimSpace(s)), "/")
	out := make([]string, 0, len(parts))
	for _, part := range parts {
		if part == "" || part == "." {
			continue
		}
		out = append(out, part)
	}
	return out
}

func validateRelativePattern(pattern string) error {
	if filepath.IsAbs(pattern) {
		return fmt.Errorf("artifact_type_roots: absolute paths are not allowed: %q", pattern)
	}
	for _, part := range splitPath(pattern) {
		if part == ".." {
			return fmt.Errorf("artifact_type_roots: path escapes plugin root: %q", pattern)
		}
	}
	return nil
}

func hasGlob(s string) bool {
	return strings.ContainsAny(s, "*?[")
}

func recordSnapshot(path string) snapshot {
	info, err := os.Stat(path)
	if err != nil {
		return snapshot{path: path}
	}
	return snapshot{path: path, exists: true, modTime: info.ModTime()}
}

func canonicalPath(path string) (string, error) {
	abs, err := filepath.Abs(path)
	if err != nil {
		return "", err
	}
	resolved, err := filepath.EvalSymlinks(abs)
	if err != nil {
		if os.IsNotExist(err) {
			return abs, nil
		}
		return "", err
	}
	return resolved, nil
}

func ensureWithinRoot(rootCanonical, candidateCanonical string) error {
	rel, err := filepath.Rel(rootCanonical, candidateCanonical)
	if err != nil {
		return err
	}
	if rel == ".." || strings.HasPrefix(rel, ".."+string(filepath.Separator)) {
		return fmt.Errorf("path %s escapes plugin root %s", candidateCanonical, rootCanonical)
	}
	return nil
}

